	// The size returned is the count of elements used.
	generateMap := func(arr []int64) map[int64]int {
		m := make(map[int64]int)
		lenArr := len(arr)

		// Iterate over all 2^lenArr subsets
		// Since lenArr <= 20, 1 << lenArr fits safely in a standard integer type.
		for i := 0; i < (1 << lenArr); i++ {
			xorSum := int64(0)
			count := 0
			for j := 0; j < lenArr; j++ {
				if (i>>j)&1 == 1 {
					xorSum ^= arr[j]
					count++
				}
			}

			// Update map: keep the maximum size for this XOR sum
			currentMax, exists := m[xorSum]
			if !exists || count > currentMax {
				m[xorSum] = count
			}
		}
		return m
	}

	mid := n / 2
	A := nums[:mid]
	B := nums[mid:]

	MapA := generateMap(A)
	MapB := generateMap(B)

	SMax := -1

	// Combine results
	for xA, sA := range MapA {
		xBTarget := target ^ xA

