			currentTotalSize := sA + sB
			if currentTotalSize > SMax {
				SMax = currentTotalSize
			}
		}
	}

	if SMax == -1 {
		return -1
	}

	// Minimum removals = Total elements - Maximum kept elements
	return int64(n - SMax)
