func solve(nums []int64, target int64) int64 {
	N := len(nums)

	// Step 1: Calculate T' = X XOR target
	fullXOR := int64(0)
	for _, num := range nums {
		fullXOR ^= num
	}
	TPrime := fullXOR ^ target

	// Step 2: Meet-in-the-Middle Split
	N_A := N / 2
	A := nums[:N_A]
	B := nums[N_A:]

	// Generate maps for both halves
	mapA := generateMap(A)
	mapB := generateMap(B)

	// Step 3: Find the minimum total size |R_A| + |R_B| such that XOR(R_A) ^ XOR(R_B) = T'
